function startFromTarget(target) {
  if (!target) return null;
  if (target.nodeType === 1) return target;
  if (target.nodeType === 3) return target.parentElement || null; // Text
  return null;
}

function closestWithin(start, selector, root, until) {
  let cur = start;
  while (cur) {
    if (until && cur.matches && cur.matches(until)) return null;
    if (cur.matches && cur.matches(selector)) return cur;
    if (cur === root) break;
    cur = cur.parentElement;
  }
  return null;
}

function isIgnored(start, ignoreSelector, root, until) {
  let cur = start;
  while (cur) {
    if (until && cur.matches && cur.matches(until)) return false;
    if (cur.matches && cur.matches(ignoreSelector)) return true;
    if (cur === root) break;
    cur = cur.parentElement;
  }
  return false;
}

export default function delegate(root, eventType, selector, handler, options) {
  if (!root || typeof root.addEventListener !== 'function') {
    throw new TypeError('delegate: root must be an Element');
  }
  if (typeof eventType !== 'string') {
    throw new TypeError('delegate: eventType must be a string');
  }
  if (typeof selector !== 'string') {
    throw new TypeError('delegate: selector must be a string');
  }
  if (typeof handler !== 'function') {
    throw new TypeError('delegate: handler must be a function');
  }

  const capture = !!options?.capture;
  const once = !!options?.once;
  const ignore = options?.ignore;
  const until = options?.until;
  const stop = !!options?.stop;

  let removed = false;
  const cleanup = () => {
    if (removed) return;
    removed = true;
    root.removeEventListener(eventType, listener, capture);
  };

  const listener = (event) => {
    const start = startFromTarget(event && event.target);
    if (!start) return;

    if (ignore && isIgnored(start, ignore, root, until)) return;

    const matched = closestWithin(start, selector, root, until);
    if (!matched) return;

    if (stop && event && typeof event.stopPropagation === 'function') {
      event.stopPropagation();
    }

    handler(event, matched);
    if (once) cleanup();
  };

  root.addEventListener(eventType, listener, capture);
  return cleanup;
}
